  quinn: { diff: "TRICKY", tone: "#ff8b3d", tldr: "She pokes + kites \u2014 W-root her kite, all-in early.", breakdown: "Quinn out-pokes you. W-root her (locks her kite), sapling-poke, and all-in early.", dos: ["W-root her (locks her kite)", "Sapling-poke her", "All-in early"], donts: ["Fight into her blind", "Poke-war from range", "Let her kite you out"], key: { slot: "E", name: "Vault (Dash/Blind)", cd: "11s", note: "Her self-peel. Root around it.", winT: "VAULT DOWN", winS: "W-Q + R her." }, hold: "Hold W to root her \u2014 the lock-on stops her kite; Q-knockback and all-in early.", tip: "W-root her (it locks her kite) \u2014 sapling-poke and all-in her early before she scales.", win: "Root her kite and all-in early." },
