  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — root him on the Heroic Swing cooldown and grind him with saplings.","breakdown":"Akshan plays around Heroic Swing. Hold W for Heroic Swing, seed brush saplings on his path, and Q-knockback resets every trade your passive heals back. Doran’s Shield blunts the poke war.","dos":["W-root when Heroic Swing is down","Bush saplings on his farm path","Q-knockback his engage"],"donts":["Eat poke without passive up","Sapling the open lane (they die)","Burn W on minions"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"W-root + sapling chain."},"win":"Root him on the Heroic Swing cooldown and grind him with saplings."},
  cassiopeia: {"diff":"HARD","tone":"#ff5d6c","tldr":"He kites you out — survive, then root him on the Miasma cooldown and grind him with saplings.","breakdown":"Cassiopeia plays around Miasma. Hold W for Miasma, seed brush saplings on his path, and Q-knockback resets every trade your passive heals back. Take Mercs / MR shard — his damage is magic. Doran’s Shield blunts the poke war.","dos":["W-root when Miasma is down","Bush saplings on his farm path","Q-knockback his engage"],"donts":["Eat poke without passive up","Sapling the open lane (they die)","Burn W on minions"],"key":{"slot":"W","name":"Miasma","cd":"12s","note":"Grounds you — dashes and movement abilities are disabled inside it.","winT":"MIASMA DOWN","winS":"W-root + sapling chain."},"win":"Root him on the Miasma cooldown and grind him with saplings."},
  galio: {"diff":"EVEN","tone":"#e8b84b","tldr":"Bait his key tool — root him on the Justice Punch cooldown and grind him with saplings.","breakdown":"Galio plays around Justice Punch. Hold W for Justice Punch, seed brush saplings on his path, and Q-knockback resets every trade your passive heals back. Take Mercs / MR shard — his damage is magic.","dos":["W-root when Justice Punch is down","Bush saplings on his farm path","Q-knockback his engage"],"donts":["Eat poke without passive up","Sapling the open lane (they die)","Burn W on minions"],"key":{"slot":"E","name":"Justice Punch","cd":"13s","note":"His dash + knockup engage. Punish him when it's down.","winT":"JUSTICE PUNCH DOWN","winS":"W-root + sapling chain."},"win":"Root him on the Justice Punch cooldown and grind him with saplings."},
